Here's how to test `DataFetcher` with modern MSTest, covering success, failure, timeout, and cancellation:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHandler("hello world", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act
        var result = await fetcher.FetchAsync("https://example.com");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_ServerError_ThrowsHttpRequestException()
    {
        var handler = new FakeHandler("", HttpStatusCode.InternalServerError);
        var fetcher = new DataFetcher(new HttpClient(handler));

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com"));
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceledException()
    {
        // Arrange — handler that delays so cancellation can fire
        using var cts = new CancellationTokenSource();
        var handler = new FakeHandler("data", HttpStatusCode.OK, delay: TimeSpan.FromSeconds(30));
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Act — cancel immediately
        cts.Cancel();

        // Assert
        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com", cts.Token));
    }

    [TestMethod]
    [Timeout(5000)] // test itself fails if it takes >5s
    public async Task FetchAsync_WithTimeout_CompletesInTime()
    {
        var handler = new FakeHandler("fast", HttpStatusCode.OK);
        var fetcher = new DataFetcher(new HttpClient(handler));

        // Pass TestContext.CancellationToken so [Timeout] can cancel cooperatively
        var result = await fetcher.FetchAsync(
            "https://example.com", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    // Reusable fake handler — no external mocking library needed
    private sealed class FakeHandler(
        string content, HttpStatusCode status, TimeSpan delay = default)
        : HttpMessageHandler
    {
        protected override async Task<HttpResponseMessage> SendAsync(
            HttpRequestMessage request, CancellationToken cancellationToken)
        {
            if (delay > TimeSpan.Zero)
            {
                await Task.Delay(delay, cancellationToken);
            }

            return new HttpResponseMessage(status)
            {
                Content = new StringContent(content),
            };
        }
    }
}
```

**Key patterns used:**

| Pattern | Why |
|---|---|
| `sealed` test class | Performance + design clarity |
| `TestContext` via constructor | Enables `readonly`, satisfies nullability |
| `Assert.ThrowsExactlyAsync<T>` | Replaces obsolete `[ExpectedException]` — lets you assert on the exception |
| `TestContext.CancellationToken` | Cooperates with `[Timeout]` — MSTest cancels the token when time expires |
| `FakeHandler` over mocking `HttpClient` | `HttpClient` can't be mocked directly; substitute the `HttpMessageHandler` |
| Separate `CancellationTokenSource` | Tests that *your code* forwards cancellation correctly |

The `[Timeout]` + `CancellationToken` combo is critical: without passing `_testContext.CancellationToken`, a hung async call would ignore the timeout and the test would hang indefinitely.
